import "next-auth";
import "next-auth/jwt";

// Augment NextAuth types to carry our custom `role` and `id` fields (Week 9).
declare module "next-auth" {
  interface Session {
    user: {
      id?: string;
      name?: string | null;
      email?: string | null;
      image?: string | null;
      role?: string;
    };
  }
}

declare module "next-auth/jwt" {
  interface JWT {
    id?: string;
    role?: string;
  }
}
